import { useEffect, useState } from "react";
import {
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
} from "recharts";
import api from "../api/api";

export default function AlertTimelineChart() {
  const [data, setData] = useState([]);

  useEffect(() => {
    api.get("/stats/timeline")
      .then(res => setData(res.data))
      .catch(err => {
        console.error("Błąd pobierania danych timeline:", err);
        setData([
          { date: "2025-05-21", count: 2 },
          { date: "2025-05-22", count: 5 },
          { date: "2025-05-23", count: 8 },
          { date: "2025-05-24", count: 3 },
          { date: "2025-05-25", count: 7 },
        ]);
      });
  }, []);

  return (
    <div className="bg-white dark:bg-gray-800 rounded-xl shadow p-6 mt-8">
      <h2 className="text-xl font-semibold mb-4">📈 Alerty na przestrzeni czasu</h2>
      <ResponsiveContainer width="100%" height={300}>
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="date" />
          <YAxis allowDecimals={false} />
          <Tooltip />
          <Line type="monotone" dataKey="count" stroke="#3b82f6" strokeWidth={2} />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}
